dslRule:
/*!id: jdt.internal.naiveastflattener.switchrule.arrow-space*/
/*!description: Adds a space before the '->' in switch labeled rules within NaiveASTFlattener for JLS12+ to align with formatter settings.*/
@severity: info
$node.isSwitchLabeledRule() ? "->" : ":" :: sourceVersionGE(12)
=> $node.isSwitchLabeledRule() ? " ->" : ":"
;;

/*!id: jdt.internal.astrewriteflattener.switchrule.arrow-space*/
/*!description: Adds a space before the '->' in switch labeled rules within ASTRewriteFlattener for JLS12+ to align with formatter settings.*/
@severity: info
getBooleanAttribute($node, org.eclipse.jdt.core.dom.SwitchCase.SWITCH_LABELED_RULE_PROPERTY) ? "->" : ":" :: sourceVersionGE(12)
=> getBooleanAttribute($node, org.eclipse.jdt.core.dom.SwitchCase.SWITCH_LABELED_RULE_PROPERTY) ? " ->" : ":"
;;

/*!id: jdt.internal.astrewriteanalyzer.switchlistrewriter.to.labeledrule*/
/*!description: Replaces the instantiation of SwitchListRewriter with SwitchListLabeledRuleRewriter for JLS12+ switch expression formatting within ASTRewriteAnalyzer.*/
@severity: info
new org.eclipse.jdt.internal.core.dom.rewrite.ASTRewriteAnalyzer.SwitchListRewriter($insertIndent) :: sourceVersionGE(12)
=> new org.eclipse.jdt.internal.core.dom.rewrite.ASTRewriteAnalyzer.SwitchListLabeledRuleRewriter($insertIndent)
;;

dslRuleAfterChange:
A hypothetical DSL rule, if statement-level replacement were supported, might look like:

for (int $i = 0; $i < $array.length; $i++) {
    $collection.add($array[$i]);
}
=>
java.util.Collections.addAll($collection, $array);
;;

// Hypothetical DSL rule if structural matching and '|' were supported:
catch ($Type1 $e) { $body$ } catch ($Type2 $e2) { $body2$ } :: $e.getName() == $e2.getName() && $body$ == $body2$ && sourceVersionGE(7)
=> catch ($Type1 | $Type2 $e) { $body$ }
;;

// A simpler hypothetical rule for a single-catch block, if '|' was supported
// (but not directly what this commit does, as it merges two blocks)
catch ($Type1 $e) { $body$ } :: sourceVersionGE(7) && isSubtypeOf($Type2, "java.lang.Throwable") && mightAlsoThrow($Type2)
=> catch ($Type1 | $Type2 $e) { $body$ }
;;

dslRule:
/*!id: jdt.internal.ast.newast.add.previewflag.default*/
/*!description: Modernizes AST.newAST(int) calls to include the new 'previewEnabled' flag, defaulting to false as per the API deprecation and replacement. This rule handles the direct deprecation of AST.newAST(int) by explicitly calling AST.newAST(int, boolean).*/
/*!severity: info*/
org.eclipse.jdt.core.dom.AST.newAST($level)
=> org.eclipse.jdt.core.dom.AST.newAST($level, false)
;;

/*!id: jdt.internal.ast.jls13.to.jls12*/
/*!description: Updates internal JDT AST API references from JLS13 to JLS12, correcting the recommended AST level for certain operations.*/
/*!severity: info*/
org.eclipse.jdt.core.dom.AST.JLS13
=> org.eclipse.jdt.core.dom.AST.JLS12
;;

/*!id: jdt.internal.ast.add-previewenabled-jls12*/
/*!description: Updates internal JDT AST traversal logic for Java 12+ features by adding a check for AST.isPreviewEnabled(). Targets AST.JLS12 API level checks.*/
/*!severity: info*/
$node.getAST().apiLevel() >= org.eclipse.jdt.core.dom.AST.JLS12
:: sourceVersionGE(12) && (instanceof($node, "org.eclipse.jdt.core.dom.BreakStatement") || instanceof($node, "org.eclipse.jdt.core.dom.SwitchCase"))
=> $node.getAST().apiLevel() >= org.eclipse.jdt.core.dom.AST.JLS12 && $node.getAST().isPreviewEnabled()
;;

/*!id: jdt.internal.ast.add-previewenabled-jls12-internal*/
/*!description: Updates internal JDT AST traversal logic for Java 12+ features by adding a check for AST.isPreviewEnabled(). Targets AST.JLS12_INTERNAL API level checks.*/
/*!severity: info*/
$node.getAST().apiLevel() >= org.eclipse.jdt.core.dom.AST.JLS12_INTERNAL
:: sourceVersionGE(12) && (instanceof($node, "org.eclipse.jdt.core.dom.BreakStatement") || instanceof($node, "org.eclipse.jdt.core.dom.SwitchCase"))
=> $node.getAST().apiLevel() >= org.eclipse.jdt.core.dom.AST.JLS12_INTERNAL && $node.getAST().isPreviewEnabled()
;;

/*!id: jdt.internal.ast.remove-ispreviewenabled-check*/
/*!description: Removes explicit checks for AST.isPreviewEnabled() from internal JDT Core DOM conditional logic. This effectively makes handling of Java 12+ features, previously guarded by the preview flag, unconditional, reflecting a revert of previous behavior.*/
/*!severity: info*/
/*!minJavaVersion: 12*/
/*!tags: jdt, internal, refactoring, java12, preview*/
org.eclipse.jdt.core.dom.AST.$astVar.isPreviewEnabled()
=> true
;;

dslRuleAfterChange:
@id: jdt.internal.typebinding.iscapture.refinement
@severity: info
this.binding.isCapture()
=> this.binding.isCapture() && !(this.binding instanceof org.eclipse.jdt.internal.compiler.lookup.CaptureBinding18)
;;

@id: jdt.internal.typebinding.iswildcardtype.broadening
@severity: info
this.binding.isWildcard()
=> this.binding.isWildcard() || this.binding instanceof org.eclipse.jdt.internal.compiler.lookup.CaptureBinding18
;;

// The modification to the 'switch' statement by adding a new 'case Binding.TYPE_PARAMETER'
// with its internal conditional logic cannot be expressed in the current TriggerPattern DSL
// as it does not support structural insertions of control flow statements like 'case' blocks.

dslRule:
/*!id: jdt.internal.astconverter.yieldstatement.previewcheck*/
/*!description: Updates internal JDT ASTConverter logic for YieldStatement to check for preview enabled status instead of JLS13_INTERNAL API level, aligning with Java 14+ preview feature handling.*/
/*!severity: info*/
/*!minJavaVersion: 14*/
this.ast.apiLevel != org.eclipse.jdt.core.dom.AST.JLS13_INTERNAL
=> !this.ast.isPreviewEnabled()
;;

/*!id: jdt.internal.typebinding.iscapture.jls18*/
/*!description: Refines internal JDT TypeBinding.isCapture() logic to exclude CaptureBinding18 instances, improving accuracy for Java 8+ type annotations.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
this.binding.isCapture()
=> this.binding.isCapture() && !(this.binding instanceof org.eclipse.jdt.internal.compiler.lookup.CaptureBinding18)
;;

/*!id: jdt.internal.typebinding.iswildcardtype.jls18*/
/*!description: Updates internal JDT TypeBinding.isWildcardType() logic to include CaptureBinding18 instances, aligning with Java 8+ type annotations and improved capture conversion.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
this.binding.isWildcard()
=> this.binding.isWildcard() || this.binding instanceof org.eclipse.jdt.internal.compiler.lookup.CaptureBinding18
;;
